import api from './api';


// ======================================
// ADD MARKS
// ======================================

export const addMarks =
async (data) => {

  const response =
    await api.post(
      '/marks',
      data
    );

  return response.data;

};


// ======================================
// GET MARKS
// ======================================

export const getMarks =
async () => {

  const response =
    await api.get('/marks');

  return response.data;

};
